class CrosshairLayer extends cc.Layer {
    private _draw: cc.DrawNode;
    private static readonly CROSS_SIZE = 20;
    private static readonly LINE_WIDTH = 1;

    onEnter(): void {
        super.onEnter();
        this._draw = new cc.DrawNode();
        this.addChild(this._draw);

        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: (touch: cc.Touch): boolean => {
                this.drawCrosshair(touch.getLocation());
                return true;
            },
            onTouchMoved: (touch: cc.Touch): void => {
                this.drawCrosshair(touch.getLocation());
            }
        }, this);
    }

    private drawCrosshair(pos: cc.Point): void {
        this._draw.clear();
        const s = CrosshairLayer.CROSS_SIZE;
        const w = CrosshairLayer.LINE_WIDTH;
        const col = cc.color(0, 255, 0, 255);

        // Horizontal line
        this._draw.drawSegment(cc.p(pos.x - s, pos.y), cc.p(pos.x + s, pos.y), w, col);
        // Vertical line
        this._draw.drawSegment(cc.p(pos.x, pos.y - s), cc.p(pos.x, pos.y + s), w, col);
        // Center dot
        this._draw.drawDot(pos, 3, cc.color(255, 0, 0, 255));
    }
}
```

