```typescript
function drawArrow(
    draw: cc.DrawNode,
    from: cc.Point,
    to: cc.Point,
    headLength: number,
    lineWidth: number,
    color: cc.Color
): void {
    // Draw the shaft
    draw.drawSegment(from, to, lineWidth, color);

    // Calculate arrowhead
    const dir = cc.pNormalize(cc.pSub(from, to));
    const headAngle = Math.PI / 6; // 30 degrees

    const left = cc.pAdd(to, cc.pRotateByAngle(
        cc.pMult(dir, headLength), cc.p(0, 0), headAngle
    ));
    const right = cc.pAdd(to, cc.pRotateByAngle(
        cc.pMult(dir, headLength), cc.p(0, 0), -headAngle
    ));

    // Draw arrowhead as a filled triangle
    draw.drawPoly([to, left, right], color, lineWidth, color);
}

// Usage:
const draw = new cc.DrawNode();
this.addChild(draw);
drawArrow(draw, cc.p(50, 100), cc.p(250, 200), 15, 2, cc.color(255, 0, 0, 255));
```

