```typescript
function drawTrajectory(
    draw: cc.DrawNode,
    startPos: cc.Point,
    velocity: cc.Point,
    gravity: number,
    duration: number
): void {
    // Calculate the trajectory as a quadratic bezier
    // End position: start + velocity*t + 0.5*g*t^2
    const endX = startPos.x + velocity.x * duration;
    const endY = startPos.y + velocity.y * duration + 0.5 * gravity * duration * duration;

    // Control point at midpoint time
    const midT = duration / 2;
    const ctrlX = startPos.x + velocity.x * midT;
    // For quadratic bezier, control = 2*midpoint - 0.5*(start+end)
    const midY = startPos.y + velocity.y * midT + 0.5 * gravity * midT * midT;
    const ctrlY = 2 * midY - 0.5 * (startPos.y + endY);

    draw.drawQuadBezier(
        startPos,
        cc.p(ctrlX, ctrlY),
        cc.p(endX, endY),
        40,
        1,
        cc.color(255, 255, 0, 180)
    );

    // Draw dots along the path for timing
    const steps = 10;
    for (let i = 0; i <= steps; i++) {
        const t = (i / steps) * duration;
        const x = startPos.x + velocity.x * t;
        const y = startPos.y + velocity.y * t + 0.5 * gravity * t * t;
        draw.drawDot(cc.p(x, y), 2, cc.color(255, 100, 0, 255));
    }
}

// Usage:
const draw = new cc.DrawNode();
this.addChild(draw);
drawTrajectory(draw, cc.p(50, 100), cc.p(200, 300), -500, 1.2);
```

```typescript
function drawRadarChart(
    draw: cc.DrawNode,
    center: cc.Point,
    radius: number,
    labels: string[],
    values: number[],  // normalized 0..1
    fillColor: cc.Color,
    lineColor: cc.Color
): void {
    const count = labels.length;
    const angleStep = (Math.PI * 2) / count;

    // Draw axis lines and rings
    for (let i = 0; i < count; i++) {
        const angle = angleStep * i - Math.PI / 2;
        const edgePt = cc.p(
            center.x + radius * Math.cos(angle),
            center.y + radius * Math.sin(angle)
        );
        draw.drawSegment(center, edgePt, 0.5, cc.color(100, 100, 100, 150));
    }

    // Draw concentric rings at 25%, 50%, 75%, 100%
    for (let ring = 1; ring <= 4; ring++) {
        const r = radius * ring / 4;
        draw.drawCircle(center, r, 0, 48, false, 0.5, cc.color(80, 80, 80, 100));
    }

    // Draw data polygon
    const verts: cc.Point[] = [];
    for (let i = 0; i < count; i++) {
        const angle = angleStep * i - Math.PI / 2;
        const r = radius * Math.max(0, Math.min(1, values[i]));
        verts.push(cc.p(
            center.x + r * Math.cos(angle),
            center.y + r * Math.sin(angle)
        ));
    }
    draw.drawPoly(verts, fillColor, 2, lineColor);

    // Draw data points
    for (const v of verts) {
        draw.drawDot(v, 4, lineColor);
    }
}

// Usage:
const draw = new cc.DrawNode();
this.addChild(draw);
drawRadarChart(
    draw, cc.p(240, 160), 100,
    ['ATK', 'DEF', 'SPD', 'HP', 'MP'],
    [0.9, 0.6, 0.8, 0.5, 0.7],
    cc.color(0, 150, 255, 60),
    cc.color(0, 150, 255, 255)
