class SelectableUnit extends cc.Node {
    private _sprite: cc.Sprite;
    private _selectionDraw: cc.DrawNode;
    private _selected: boolean = false;

    constructor(frameName: string) {
        super();
        this._sprite = new cc.Sprite(
            cc.spriteFrameCache.getSpriteFrame(frameName)
        );
        this.addChild(this._sprite);

        this._selectionDraw = new cc.DrawNode();
        this.addChild(this._selectionDraw, -1);
    }

    setSelected(selected: boolean): void {
        this._selected = selected;
        this._selectionDraw.clear();

        if (!selected) return;

        const size = this._sprite.getContentSize();
        const hw = size.width / 2 + 4;
        const hh = size.height / 2 + 4;

        // Draw selection ring
        this._selectionDraw.drawCircle(
            cc.p(0, 0), Math.max(hw, hh),
            0, 32, false, 2,
            cc.color(0, 255, 0, 200)
        );

        // Draw corner brackets
        const col = cc.color(0, 255, 0, 255);
        const len = 8;
        // Top-left
        this._selectionDraw.drawSegment(cc.p(-hw, hh), cc.p(-hw + len, hh), 1, col);
        this._selectionDraw.drawSegment(cc.p(-hw, hh), cc.p(-hw, hh - len), 1, col);
        // Top-right
        this._selectionDraw.drawSegment(cc.p(hw, hh), cc.p(hw - len, hh), 1, col);
        this._selectionDraw.drawSegment(cc.p(hw, hh), cc.p(hw, hh - len), 1, col);
        // Bottom-left
        this._selectionDraw.drawSegment(cc.p(-hw, -hh), cc.p(-hw + len, -hh), 1, col);
        this._selectionDraw.drawSegment(cc.p(-hw, -hh), cc.p(-hw, -hh + len), 1, col);
        // Bottom-right
        this._selectionDraw.drawSegment(cc.p(hw, -hh), cc.p(hw - len, -hh), 1, col);
        this._selectionDraw.drawSegment(cc.p(hw, -hh), cc.p(hw, -hh + len), 1, col);
    }
}

// Usage:
const unit = new SelectableUnit('soldier_idle.png');
unit.setPosition(240, 160);
this.addChild(unit);
unit.setSelected(true);
```

