class DebugCharacter extends cc.Node {
    private _sprite: cc.Sprite;
    private _debugDraw: cc.DrawNode;
    private _hitboxRadius: number = 20;
    private _attackRange: number = 50;
    private _showDebug: boolean = true;

    constructor(spritePath: string) {
        super();
        this._sprite = new cc.Sprite(spritePath);
        this.addChild(this._sprite);

        this._debugDraw = new cc.DrawNode();
        this.addChild(this._debugDraw, 100);
        this.scheduleUpdate();
    }

    toggleDebug(): void {
        this._showDebug = !this._showDebug;
        this._debugDraw.setVisible(this._showDebug);
    }

    update(dt: number): void {
        if (!this._showDebug) return;
        this._debugDraw.clear();

        // Hitbox circle (green)
        this._debugDraw.drawCircle(
            cc.p(0, 0), this._hitboxRadius,
            0, 24, false, 1,
            cc.color(0, 255, 0, 150)
        );

        // Attack range (red, dashed effect via dots)
        const pts: cc.Point[] = [];
        for (let i = 0; i < 36; i++) {
            const a = (i / 36) * Math.PI * 2;
            pts.push(cc.p(
                this._attackRange * Math.cos(a),
                this._attackRange * Math.sin(a)
            ));
        }
        this._debugDraw.drawDots(pts, 1, cc.color(255, 0, 0, 100));

        // Origin crosshair
        this._debugDraw.drawSegment(cc.p(-5, 0), cc.p(5, 0), 0.5, cc.color(255, 255, 0, 200));
        this._debugDraw.drawSegment(cc.p(0, -5), cc.p(0, 5), 0.5, cc.color(255, 255, 0, 200));
    }
}
```

The DrawNode is a child of the character node, so its coordinates are in local space — `cc.p(0, 0)` is the character's anchor point. Set a high z-order so debug shapes render above the sprite.

```typescript
function drawLineChart(
    draw: cc.DrawNode,
    origin: cc.Point,
    width: number,
    height: number,
    data: number[]
): void {
    if (data.length < 2) return;
    draw.clear();

    const axisColor = cc.color(200, 200, 200, 255);
    const lineColor = cc.color(0, 200, 255, 255);
    const dotColor = cc.color(255, 255, 0, 255);
    const gridColor = cc.color(80, 80, 80, 100);

    // Draw axes
    draw.drawSegment(origin, cc.p(origin.x, origin.y + height), 1, axisColor);
    draw.drawSegment(origin, cc.p(origin.x + width, origin.y), 1, axisColor);

    // Horizontal grid lines
    const gridLines = 4;
    for (let i = 1; i <= gridLines; i++) {
        const y = origin.y + (height / gridLines) * i;
        draw.drawSegment(
            cc.p(origin.x, y),
            cc.p(origin.x + width, y),
            0.5, gridColor
        );
    }

    // Normalize and plot data
    const maxVal = Math.max(...data);
    const minVal = Math.min(...data);
    const range = maxVal - minVal || 1;
    const stepX = width / (data.length - 1);

    const points: cc.Point[] = data.map((val, i) => {
        const nx = origin.x + i * stepX;
        const ny = origin.y + ((val - minVal) / range) * height;
        return cc.p(nx, ny);
    });

    // Draw line segments
    for (let i = 0; i < points.length - 1; i++) {
        draw.drawSegment(points[i], points[i + 1], 1.5, lineColor);
    }

    // Draw data dots
    draw.drawDots(points, 3, dotColor);
}

// Usage:
const draw = new cc.DrawNode();
this.addChild(draw);
const data = [10, 25, 15, 40, 30, 55, 45, 60];
drawLineChart(draw, cc.p(50, 50), 380, 220, data);
```

