class GlowEffect extends cc.Layer {
    private _glowDraw: cc.DrawNode;
    private _normalDraw: cc.DrawNode;

    onEnter(): void {
        super.onEnter();

        // Background sprite
        const bg = new cc.Sprite('res/bg_dark.png');
        bg.setPosition(240, 160);
        this.addChild(bg);

        // Normal draw node (standard alpha blending)
        this._normalDraw = new cc.DrawNode();
        this.addChild(this._normalDraw, 1);

        // Glow draw node (additive blending)
        this._glowDraw = new cc.DrawNode();
        this._glowDraw.setBlendFunc(cc.SRC_ALPHA, cc.ONE);
        this.addChild(this._glowDraw, 2);

        this.drawScene();
    }

    private drawScene(): void {
        const center = cc.p(240, 160);

        // Solid circle (normal blending)
        this._normalDraw.drawCircle(
            center, 30, 0, 32, false, 2,
            cc.color(255, 200, 0, 255)
        );

        // Glow halo (additive — brightens underlying pixels)
        for (let i = 3; i >= 1; i--) {
            const r = 30 + i * 20;
            const alpha = Math.floor(60 / i);
            this._glowDraw.drawDot(
                center, r,
                cc.color(255, 150, 0, alpha)
            );
        }
    }
}
```

Additive blending (`SRC_ALPHA, ONE`) adds the drawn color to whatever is behind it, creating a glow. Using multiple concentric translucent dots with decreasing alpha produces a soft halo effect on top of the normal scene.

```typescript
class PathEditor extends cc.Layer {
    private _draw: cc.DrawNode;
    private _points: cc.Point[] = [];
    private static readonly DOT_RADIUS = 6;
    private static readonly MIN_POINTS = 2;

    onEnter(): void {
        super.onEnter();
        this._draw = new cc.DrawNode();
        this.addChild(this._draw);

        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: (touch: cc.Touch): boolean => {
                this.addWaypoint(touch.getLocation());
                return true;
            }
        }, this);
    }

    private addWaypoint(pos: cc.Point): void {
        this._points.push(pos);
        this.redraw();
    }

    clearPath(): void {
        this._points = [];
        this._draw.clear();
    }

    getPoints(): cc.Point[] {
        return this._points.slice();
    }

    private redraw(): void {
        this._draw.clear();
        const pts = this._points;

        // Draw waypoint dots
        for (let i = 0; i < pts.length; i++) {
            const isFirst = i === 0;
            const color = isFirst
                ? cc.color(0, 255, 0, 255)
                : cc.color(255, 255, 0, 255);
            this._draw.drawDot(
                pts[i], PathEditor.DOT_RADIUS, color
            );
        }

        // Draw straight-line connections
        for (let i = 0; i < pts.length - 1; i++) {
            this._draw.drawSegment(
                pts[i], pts[i + 1], 0.5,
                cc.color(100, 100, 100, 150)
            );
        }

        // Draw smooth Catmull-Rom spline
        if (pts.length >= PathEditor.MIN_POINTS) {
            this._draw.drawCatmullRom(
                pts, 50, 2,
                cc.color(0, 200, 255, 255)
            );
        }
    }
}

// Usage:
const editor = new PathEditor();
this.addChild(editor);
// Touch screen to add waypoints; path updates in real-time.
```

