```typescript
class ConnectDotsScene extends cc.Scene {
    private _draw: cc.DrawNode;
    private _lineDraw: cc.DrawNode;
    private _targets: cc.Point[] = [];
    private _connected: cc.Point[] = [];
    private _currentIndex: number = 0;
    private static readonly HIT_RADIUS = 25;
    private static readonly DOT_RADIUS = 12;

    onEnter(): void {
        super.onEnter();

        // Background
        const bg = cc.LayerColor.create(cc.color(30, 30, 50, 255));
        this.addChild(bg);

        // Line layer (below dots)
        this._lineDraw = new cc.DrawNode();
        this.addChild(this._lineDraw, 1);

        // Dot layer
        this._draw = new cc.DrawNode();
        this.addChild(this._draw, 2);

        this.setupPuzzle();
        this.drawDots();
        this.registerTouch();
    }

    private setupPuzzle(): void {
        this._targets = [
            cc.p(100, 80), cc.p(200, 200), cc.p(300, 100),
            cc.p(380, 220), cc.p(300, 280), cc.p(160, 260)
        ];
    }

    private drawDots(): void {
        this._draw.clear();
        for (let i = 0; i < this._targets.length; i++) {
            const isNext = i === this._currentIndex;
            const isDone = i < this._currentIndex;
            const color = isDone
                ? cc.color(0, 200, 0, 255)
                : isNext
                    ? cc.color(255, 255, 0, 255)
                    : cc.color(150, 150, 150, 150);
            this._draw.drawDot(
                this._targets[i],
                ConnectDotsScene.DOT_RADIUS,
                color
            );
        }
    }

    private registerTouch(): void {
        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: (touch: cc.Touch): boolean => {
                this.handleTap(touch.getLocation());
                return true;
            }
        }, this);
    }

    private handleTap(pos: cc.Point): void {
        if (this._currentIndex >= this._targets.length) return;
        const target = this._targets[this._currentIndex];
        const dist = cc.pDistance(pos, target);
        if (dist > ConnectDotsScene.HIT_RADIUS) return;

        this._connected.push(target);
        this._currentIndex++;

        // Draw connecting lines
        this._lineDraw.clear();
        for (let i = 0; i < this._connected.length - 1; i++) {
            this._lineDraw.drawSegment(
                this._connected[i], this._connected[i + 1],
                3, cc.color(0, 200, 255, 255)
            );
        }

        this.drawDots();

        if (this._currentIndex >= this._targets.length) {
            // Close the shape
            this._lineDraw.drawSegment(
                this._connected[this._connected.length - 1],
                this._connected[0],
                3, cc.color(0, 200, 255, 255)
            );
        }
    }
}
```

```typescript
drawCardinalSpline(
    config: cc.Point[],
    tension: number,
    segments: number,
    lineWidth: number,
    color?: cc.Color
): void
```

Parameters:
- `config: cc.Point[]` — array of control points the spline passes through
- `tension: number` — curve tightness: 0 = Catmull-Rom (smooth), 1 = straight lines between points
- `segments: number` — number of line segments for approximation
- `lineWidth: number` — curve thickness in pixels
- `color?: cc.Color` — optional curve color

Return type: `void`

Example:
```typescript
const draw = new cc.DrawNode();
this.addChild(draw);

const pts: cc.Point[] = [cc.p(0, 100), cc.p(80, 200), cc.p(160, 50), cc.p(240, 180)];

// Smooth curve (tension 0)
draw.drawCardinalSpline(pts, 0, 30, 2, cc.color(255, 0, 0, 255));

// Tighter curve (tension 0.5)
draw.drawCardinalSpline(pts, 0.5, 30, 2, cc.color(0, 255, 0, 255));
```

```typescript
// Quadratic Bezier — 1 control point
drawQuadBezier(
    origin: cc.Point,
    control: cc.Point,
    destination: cc.Point,
    segments: number,
    lineWidth: number,
    color?: cc.Color
): void

// Cubic Bezier — 2 control points
drawCubicBezier(
    origin: cc.Point,
    control1: cc.Point,
    control2: cc.Point,
    destination: cc.Point,
    segments: number,
    lineWidth: number,
    color?: cc.Color
): void
```

Both return `void`. The key difference is quadratic uses one `control` point for simple arcs, while cubic uses `control1` and `control2` for more complex S-shaped curves.

Example:
```typescript
const draw: cc.DrawNode = new cc.DrawNode();
this.addChild(draw);

// Quadratic (3 points)
draw.drawQuadBezier(
    cc.p(0, 0), cc.p(100, 200), cc.p(200, 0),
    30, 2, cc.color(255, 0, 0, 255)
);

// Cubic (4 points)
draw.drawCubicBezier(
    cc.p(0, 0), cc.p(50, 200), cc.p(150, -100), cc.p(200, 100),
    30, 2, cc.color(0, 0, 255, 255)
);
```

