// Usage:
const draw: cc.DrawNode = cc.DrawNode.create();
this.addChild(draw);

const hexVerts: cc.Point[] = [];
for (let i = 0; i < 6; i++) {
    const angle: number = (Math.PI / 3) * i - Math.PI / 2;
    hexVerts.push(cc.p(240 + 60 * Math.cos(angle), 160 + 60 * Math.sin(angle)));
}

