The `PolyStyle` interface keeps styling separate from geometry, making it reusable across different shapes.

Simply call multiple draw methods on the same `cc.DrawNode` instance. Each call can specify its own color independently:

```typescript
const draw = new cc.DrawNode();
this.addChild(draw);

// Red dot
draw.drawDot(cc.p(50, 100), 10, cc.color(255, 0, 0, 255));

// Blue line
draw.drawSegment(cc.p(100, 50), cc.p(300, 50), 2, cc.color(0, 0, 255, 255));

// Green rectangle
draw.drawRect(
    cc.p(150, 100), cc.p(250, 180),
    cc.color(0, 255, 0, 100), 2, cc.color(0, 200, 0, 255)
);

// Yellow circle
draw.drawCircle(cc.p(350, 150), 40, 0, 32, false, 2, cc.color(255, 255, 0, 255));
```

All shapes accumulate in the DrawNode's buffer and render together in one draw call. Each method's color parameter overrides `setDrawColor`. Call `draw.clear()` to erase all shapes at once.

```typescript
class TouchDebugOverlay extends cc.Layer {
    private _draw: cc.DrawNode;
    private _touchStart: cc.Point | null = null;
    private _touchCurrent: cc.Point | null = null;
    private _touchStartTime: number = 0;

    onEnter(): void {
        super.onEnter();
        this._draw = new cc.DrawNode();
        this.addChild(this._draw, 1000);
        this.scheduleUpdate();

        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: false,
            onTouchBegan: (touch: cc.Touch): boolean => {
                this._touchStart = touch.getLocation();
                this._touchCurrent = touch.getLocation();
                this._touchStartTime = Date.now();
                return true;
            },
            onTouchMoved: (touch: cc.Touch): void => {
                this._touchCurrent = touch.getLocation();
            },
            onTouchEnded: (): void => {
                this._touchStart = null;
                this._touchCurrent = null;
                this._draw.clear();
            }
        }, this);
    }

    update(dt: number): void {
        if (!this._touchStart || !this._touchCurrent) return;
        this._draw.clear();

        // Touch origin
        this._draw.drawDot(this._touchStart, 6, cc.color(0, 255, 0, 200));

        // Current position
        this._draw.drawDot(this._touchCurrent, 4, cc.color(255, 255, 0, 255));

        // Direction line
        this._draw.drawSegment(
            this._touchStart, this._touchCurrent,
            1, cc.color(255, 255, 255, 150)
        );

        // Velocity arrow (exaggerated)
        const delta = cc.pSub(this._touchCurrent, this._touchStart);
        const elapsed = (Date.now() - this._touchStartTime) / 1000;
        if (elapsed > 0.01) {
            const vel = cc.pMult(delta, 1 / elapsed);
            const velEnd = cc.pAdd(this._touchCurrent, cc.pMult(cc.pNormalize(vel), 30));
            this._draw.drawSegment(
                this._touchCurrent, velEnd,
                2, cc.color(255, 100, 0, 255)
            );
        }

        // Distance circle
        const dist = cc.pDistance(this._touchStart, this._touchCurrent);
        this._draw.drawCircle(
            this._touchStart, dist, 0, 32,
            false, 0.5, cc.color(100, 100, 255, 80)
        );
    }
}
```

Redraw the shape each frame in `update()`, varying the parameters over time. Always call `clear()` first:

```typescript
class PulsingCircle extends cc.Layer {
    private _draw: cc.DrawNode;
    private _time: number = 0;
    private static readonly BASE_RADIUS = 40;
    private static readonly PULSE_AMOUNT = 15;
    private static readonly PULSE_SPEED = 3;

    onEnter(): void {
        super.onEnter();
        this._draw = new cc.DrawNode();
        this.addChild(this._draw);
        this.scheduleUpdate();
    }

    update(dt: number): void {
        this._time += dt;
        this._draw.clear();

        const radius = PulsingCircle.BASE_RADIUS +
            Math.sin(this._time * PulsingCircle.PULSE_SPEED) * PulsingCircle.PULSE_AMOUNT;

        const alpha = Math.floor(128 + 127 * Math.sin(this._time * PulsingCircle.PULSE_SPEED));

        this._draw.drawDot(
            cc.p(240, 160),
            radius,
            cc.color(0, 200, 255, alpha)
        );

        this._draw.drawCircle(
            cc.p(240, 160), radius, 0, 32,
            false, 2, cc.color(0, 255, 255, 255)
        );
    }
}
```

The pattern: `scheduleUpdate()` -> `update()` calls `clear()` then redraws with time-varying parameters. This works for any animated shape — just change the position, size, color, or vertex positions based on `this._time`.

```typescript
function drawGrid(
    draw: cc.DrawNode,
    cellSize: number,
    majorEvery: number,
    winSize: cc.Size
): void {
    draw.clear();
    const minorColor = cc.color(60, 60, 60, 100);
    const majorColor = cc.color(100, 100, 100, 180);
    const axisColor = cc.color(150, 150, 150, 255);

    const cols = Math.ceil(winSize.width / cellSize);
    const rows = Math.ceil(winSize.height / cellSize);

    // Vertical lines
    for (let c = 0; c <= cols; c++) {
        const x = c * cellSize;
        const isMajor = c % majorEvery === 0;
        draw.drawSegment(
            cc.p(x, 0), cc.p(x, winSize.height),
            isMajor ? 1 : 0.5,
            isMajor ? majorColor : minorColor
        );
    }

    // Horizontal lines
    for (let r = 0; r <= rows; r++) {
        const y = r * cellSize;
        const isMajor = r % majorEvery === 0;
        draw.drawSegment(
            cc.p(0, y), cc.p(winSize.width, y),
            isMajor ? 1 : 0.5,
            isMajor ? majorColor : minorColor
        );
    }

    // Origin axes
    draw.drawSegment(cc.p(0, 0), cc.p(winSize.width, 0), 1.5, axisColor);
    draw.drawSegment(cc.p(0, 0), cc.p(0, winSize.height), 1.5, axisColor);
}

// Usage:
const gridDraw = new cc.DrawNode();
this.addChild(gridDraw, -1);
const winSize = cc.director.getWinSize();
drawGrid(gridDraw, 32, 4, winSize); // 32px cells, major every 4
```

```typescript
class BezierPathScene extends cc.Layer {
    onEnter(): void {
        super.onEnter();

        const p0 = cc.p(50, 100);
        const c1 = cc.p(100, 350);
        const c2 = cc.p(350, 50);
        const p3 = cc.p(430, 280);

        // 1. Visualize the path with DrawNode
        const draw = new cc.DrawNode();
        this.addChild(draw);

        // Control points and handles
        draw.drawDot(p0, 4, cc.color(0, 255, 0, 255));
        draw.drawDot(p3, 4, cc.color(255, 0, 0, 255));
        draw.drawDot(c1, 3, cc.color(255, 255, 0, 150));
        draw.drawDot(c2, 3, cc.color(255, 255, 0, 150));
        draw.drawSegment(p0, c1, 0.5, cc.color(255, 255, 255, 80));
        draw.drawSegment(p3, c2, 0.5, cc.color(255, 255, 255, 80));

        // The curve itself
        draw.drawCubicBezier(p0, c1, c2, p3, 50, 2, cc.color(0, 200, 255, 200));

        // 2. Move a sprite along the same bezier
        const sprite = new cc.Sprite('res/hero.png');
        sprite.setPosition(p0);
        this.addChild(sprite);

        const bezierConfig: cc.BezierConfig = [
            c1, c2, p3
        ];
        const moveAction = cc.bezierTo(2.0, bezierConfig);
        const repeatAction = cc.sequence(
            moveAction,
            cc.place(p0),
            cc.delayTime(0.5)
        ).repeatForever();

        sprite.runAction(repeatAction);
    }
}
```

The DrawNode renders the static path preview, while `cc.bezierTo` uses the same control points to animate the sprite. This lets players or designers see the trajectory visually.
